// ============================================================================
// HoneyGrid — detekcja: atak brute force z jednego IP (Tydzień 5)
// MITRE ATT&CK: T1110.001 (Brute Force: Password Guessing), taktyka: Credential Access
//
// Logika: zliczamy nieudane logowania (EventType == 'login.failed') per
// AttackerIp w 5-minutowych koszykach (bin). Pojedynczy atakujący, który
// przekroczy 15 nieudanych prób w 5 minut, to klasyczny zautomatyzowany
// brute force (Hydra/Medusa robią setki prób na minutę — człowiek mylący
// hasło nie zbliży się do tego progu).
//
// Próg (>15 prób / 5 min): WSTĘPNY — dobrany tak, by odsiać pojedyncze
// skany i pomyłki, a złapać narzędzia automatyczne. Do strojenia po
// obserwacji realnego ruchu na honeypotach (Tydzień 5, dzień 4 — po
// ponownym wdrożeniu środowiska). UWAGA: brak żywego workspace w trakcie
// pisania — zapytanie zweryfikowane konstrukcyjnie, nie na danych.
//
// Kolumny końcowej projekcji MUSZĄ zawierać AttackerIp — to kolumna
// mapowana na encję IP w regule analitycznej (entityMappings).
// ============================================================================
Cowrie_CL
| where EventType == 'login.failed'
| summarize FailedAttempts = count(), TargetedAccounts = dcount(Username), FirstSeen = min(TimeGenerated), LastSeen = max(TimeGenerated) by AttackerIp, bin(TimeGenerated, 5m)
| where FailedAttempts > 15
| project AttackerIp, FailedAttempts, TargetedAccounts, FirstSeen, LastSeen

variables.$fxv#1:
// ============================================================================
// HoneyGrid — detekcja: rozproszony brute force na jedno konto (Tydzień 5)
// MITRE ATT&CK: T1110.001 (Brute Force: Password Guessing), taktyka: Credential Access
//
// Logika: odwrotność detekcji "jeden IP, wiele prób" — tu wiele RÓŻNYCH
// adresów IP (botnet / proxy rotation) atakuje to samo konto (Username)
// w oknie 1 godziny. Per-IP progi tego nie złapią (każdy IP robi mało
// prób), dlatego grupujemy po Username i liczymy dcount(AttackerIp).
//
// Próg (>5 unikalnych IP / 1 h na jedno konto): WSTĘPNY — legalny ruch
// na honeypocie nie istnieje, więc nawet kilka IP na to samo konto to
// silny sygnał kampanii rozproszonej. Do strojenia po realnym ruchu
// (Tydzień 5, dzień 4). UWAGA: brak żywego workspace w trakcie pisania —
// zapytanie zweryfikowane konstrukcyjnie, nie na danych.
//
// Kolumny końcowej projekcji MUSZĄ zawierać Username — to kolumna
// mapowana na encję Account w regule analitycznej (entityMappings).
// ============================================================================
Cowrie_CL
| where EventType == 'login.failed'
| summarize AttackingIps = dcount(AttackerIp), FailedAttempts = count() by Username, bin(TimeGenerated, 1h)
| where AttackingIps > 5
| project Username, AttackingIps, FailedAttempts

variables.$fxv#2:
// ============================================================================
// HoneyGrid — detekcja: password spraying (Tydzień 5)
// MITRE ATT&CK: T1110.003 (Brute Force: Password Spraying), taktyka: Credential Access
//
// Logika: jeden AttackerIp próbuje WIELU różnych kont (Username), ale na
// każde konto przypada mało prób — atakujący testuje 1-2 popularne hasła
// na szerokiej liście kont, świadomie unikając progów per-konto (lockout
// / detekcji brute force). Sygnatura: dużo unikalnych kont, niski
// stosunek prób do kont (TotalAttempts < SprayedAccounts * 3, czyli
// średnio mniej niż 3 próby na konto — powyżej tego to już zwykły
// brute force, łapany przez regułę brute-force-single-ip).
//
// Progi (>8 kont / 1 h, <3 próby na konto): WSTĘPNE — do strojenia po
// realnym ruchu (Tydzień 5, dzień 4). UWAGA: brak żywego workspace w
// trakcie pisania — zapytanie zweryfikowane konstrukcyjnie, nie na danych.
//
// Kolumny końcowej projekcji MUSZĄ zawierać AttackerIp — to kolumna
// mapowana na encję IP w regule analitycznej (entityMappings).
// ============================================================================
Cowrie_CL
| where EventType == 'login.failed'
| summarize SprayedAccounts = dcount(Username), TotalAttempts = count() by AttackerIp, bin(TimeGenerated, 1h)
| where SprayedAccounts > 8 and TotalAttempts < SprayedAccounts * 3
| project AttackerIp, SprayedAccounts, TotalAttempts

variables.$fxv#3:
// ============================================================================
// HoneyGrid — detekcja: udane logowanie po fali nieudanych prób (Tydzień 5)
// MITRE ATT&CK: T1078 (Valid Accounts), taktyki: Initial Access, Persistence
// Severity: HIGH — to NIE jest szum: udany login po serii porażek oznacza,
// że bot "wszedł" do honeypota (Cowrie celowo wpuszcza po N próbach) i za
// chwilę zacznie post-exploitation (pobieranie malware, komendy 'command') —
// najcenniejszy moment obserwacyjny całego projektu.
//
// Logika (wzorzec let + join):
//   1. failures: IP-y z >= 5 nieudanymi logowaniami w oknie zapytania
//      (okno = queryPeriod reguły, PT1H — celowo BEZ bin(), żeby uniknąć
//      konfliktu kolumn TimeGenerated przy join; let projektuje wyłącznie
//      AttackerIp + FailedCount, więc join nie duplikuje kolumn czasu).
//   2. join kind=inner z udanymi logowaniami (login.success) po AttackerIp —
//      ten sam adres najpierw się dobijał, potem wszedł.
//
// Próg (>= 5 porażek przed sukcesem): WSTĘPNY — do strojenia po realnym
// ruchu (Tydzień 5, dzień 4). UWAGA: brak żywego workspace w trakcie
// pisania — zapytanie zweryfikowane konstrukcyjnie, nie na danych.
//
// Końcowa projekcja MUSI zawierać AttackerIp (encja IP), Username (encja
// Account) i SensorId (encja Host) — entityMappings reguły analitycznej.
// ============================================================================
let failures = Cowrie_CL
    | where EventType == 'login.failed'
    | summarize FailedCount = count() by AttackerIp
    | where FailedCount >= 5;
Cowrie_CL
| where EventType == 'login.success'
| join kind=inner failures on AttackerIp
| project TimeGenerated, AttackerIp, Username, SensorId, FailedCount

